prompt --application/shared_components/plugins/region_type/page_anchor_navigator
begin
wwv_flow_imp_shared.create_plugin(
 p_id=>wwv_flow_imp.id(13389925044587127)
,p_plugin_type=>'REGION TYPE'
,p_name=>'PAGE_ANCHOR_NAVIGATOR'
,p_display_name=>'Page Anchor Navigator'
,p_javascript_file_urls=>'#PLUGIN_FILES#page_anchor_navigator#MIN#.js'
,p_css_file_urls=>'#PLUGIN_FILES#page_anchor_navigator#MIN#.css'
,p_plsql_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'procedure render (',
'    p_region  in            apex_plugin.t_region,',
'    p_plugin  in            apex_plugin.t_plugin,',
'    p_param   in            apex_plugin.t_region_render_param,',
'    p_result  in out nocopy apex_plugin.t_region_render_result',
')',
'is',
'l_scroll_off  varchar2(10) := nvl(p_region.attributes.get_varchar2(''scroll_offset''),  ''100'');',
'l_anim_speed  varchar2(10) := nvl(p_region.attributes.get_varchar2(''animation_speed''), ''200'');',
'l_show_parent varchar2(1)  := nvl(p_region.attributes.get_varchar2(''show_parent''),     ''Y'');',
'l_ind_color   varchar2(30) := nvl(p_region.attributes.get_varchar2(''indicator_color''), ''#2563eb'');',
'l_track_color varchar2(30) := nvl(p_region.attributes.get_varchar2(''track_color''),     ''#d1d5db'');',
'l_text_color varchar2(30) := nvl(p_region.attributes.get_varchar2(''text_color''),     ''#374151'');',
'l_show_overflow varchar2(1)  := nvl(p_region.attributes.get_varchar2(''show_overflow''),     ''Y'');',
'',
'begin',
'    sys.htp.p(''<nav id="page-pan" role="navigation" aria-label="Page Navigation"'');',
'    sys.htp.p(''     data-scroll-offset="''    || apex_escape.html_attribute(l_scroll_off)  || ''"'');',
'    sys.htp.p(''     data-animation-speed="''  || apex_escape.html_attribute(l_anim_speed)  || ''"'');',
'    sys.htp.p(''     data-show-parent="''      || apex_escape.html_attribute(l_show_parent) || ''"'');',
'    sys.htp.p(''     data-show-overflow="''      || apex_escape.html_attribute(l_show_overflow) || ''"'');',
'    sys.htp.p(''     data-text-color="''       || apex_escape.html_attribute(l_text_color) || ''"'');',
'    sys.htp.p(''     data-indicator-color="''  || apex_escape.html_attribute(l_ind_color)   || ''"'');',
'    sys.htp.p(''     data-track-color="''      || apex_escape.html_attribute(l_track_color) || ''">'');',
'    sys.htp.p(''    <div class="pan-track">'');',
'    sys.htp.p(''        <div class="pan-track-indicator" id="pan-indicator"></div>'');',
'    sys.htp.p(''    </div>'');',
'    sys.htp.p(''    <ul id="pan-list"></ul>'');',
'    sys.htp.p(''</nav>'');',
'',
'sys.htp.p(''<!-- DEBUG: off='' || p_region.attributes.get_varchar2(''scroll_offset'')',
'    || '' ind='' || p_region.attributes.get_varchar2(''indicator_color'') || '' -->'');',
'end render;'))
,p_api_version=>3
,p_render_function=>'render'
,p_substitute_attributes=>true
,p_version_scn=>45281212830627
,p_subscribe_plugin_settings=>true
,p_help_text=>'Designed to keep control over big forms, documentations and pages that have a lot of content.'
,p_version_identifier=>'1.0'
